import { createAsyncThunk, createSlice } from '@reduxjs/toolkit';

type User = { id: string };

export const loadUser = createAsyncThunk('user/load', (id: string) =>
  fetch(`/api/u/${id}`).then((r) => r.json() as Promise<User>)
);

const userSlice = createSlice({
  name: 'user',
  initialState: { data: null as User | null, status: 'idle' as 'idle' | 'loading' | 'succeeded' },
  reducers: {},
  extraReducers: b =>
    b
      .addCase(loadUser.pending, s => { s.status = 'loading'; })
      .addCase(loadUser.fulfilled, (s, a) => {
        s.status = 'succeeded';
        s.data = a.payload;
      }),
});

